  ('heelevel3-d592fc58-moex-00035', 'heelevel3-d592fc58', 'heelevel3-d592fc58-moex-114-a9c8416b', 'sub-heelevel3-d592fc58-03', NULL, 'essay', '請回答下列問題：（每小題 10分，共 20分）
